#!/usr/bin/env bash
set -euo pipefail

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
cd "$ROOT"

RESULTS_DIR="$ROOT/results"

# Ensure base eval exists (generated by earlier pipeline); fail fast if not.
if [ ! -f "$ROOT/data/processed/eval_test.jsonl" ]; then
  echo "data/processed/eval_test.jsonl not found. Run scripts/run_paper_experiments.sh first."
  exit 1
fi

# 1) Name-masked + number-stripped eval
python -m training.mask_eval_queries \
  --eval-file data/processed/eval_test.jsonl \
  --output data/processed/eval_test_masked.jsonl

# 2) External evals (NLP4LP, OptiBench/Resocratic, NL4Opt competition)
python -m training.external.nlp4lp_loader \
  --split test \
  --eval-out data/processed/nlp4lp_eval.jsonl \
  --coverage-out "$RESULTS_DIR/nlp4lp_coverage.json" || true

python -m training.external.optibench_loader \
  --eval-out data/processed/resocratic_eval.jsonl \
  --coverage-out "$RESULTS_DIR/resocratic_coverage.json" || true

python -m training.external.nl4opt_comp_loader \
  --eval-out data/processed/nl4opt_comp_eval.jsonl \
  --coverage-out "$RESULTS_DIR/nl4opt_comp_coverage.json" || true

# 3) Baselines on key settings with bootstrap CIs
# (1) normal test
python -m training.run_baselines \
  --splits data/processed/splits.json \
  --split test \
  --eval-file data/processed/eval_test.jsonl \
  --k 10 \
  --baselines bm25 tfidf sbert sbert_finetuned \
  --results-dir "$RESULTS_DIR" \
  --dataset-name test_normal \
  --bootstrap 1000 \
  --ci-metrics "P@1,MRR@10,nDCG@10"
cp "$RESULTS_DIR/baselines_test_normal.csv" "$RESULTS_DIR/baselines_test_normal.csv" 2>/dev/null || true

# (2) masked test
python -m training.run_baselines \
  --splits data/processed/splits.json \
  --split test \
  --eval-file data/processed/eval_test_masked.jsonl \
  --k 10 \
  --baselines bm25 tfidf sbert sbert_finetuned \
  --results-dir "$RESULTS_DIR" \
  --dataset-name test_masked \
  --bootstrap 1000 \
  --ci-metrics "P@1,MRR@10,nDCG@10"
cp "$RESULTS_DIR/baselines_test_masked.csv" "$RESULTS_DIR/baselines_test_masked.csv" 2>/dev/null || true

# (3) ReSocratic (OptiBench synthetic)
if [ -f "$ROOT/data/processed/resocratic_eval.jsonl" ]; then
  python -m training.run_baselines \
    --eval-file data/processed/resocratic_eval.jsonl \
    --k 10 \
    --baselines bm25 tfidf sbert sbert_finetuned \
    --results-dir "$RESULTS_DIR" \
    --dataset-name resocratic \
    --bootstrap 1000 \
    --ci-metrics "P@1,MRR@10,nDCG@10"
  cp "$RESULTS_DIR/baselines_resocratic.csv" "$RESULTS_DIR/baselines_resocratic.csv" 2>/dev/null || true
else
  echo "ReSocratic eval not found; skipping baselines_resocratic.csv."
fi

# (4) NL4Opt competition
if [ -f "$ROOT/data/processed/nl4opt_comp_eval.jsonl" ]; then
  python -m training.run_baselines \
    --eval-file data/processed/nl4opt_comp_eval.jsonl \
    --k 10 \
    --baselines bm25 tfidf sbert sbert_finetuned \
    --results-dir "$RESULTS_DIR" \
    --dataset-name nl4opt \
    --bootstrap 1000 \
    --ci-metrics "P@1,MRR@10,nDCG@10"
  cp "$RESULTS_DIR/baselines_nl4opt.csv" "$RESULTS_DIR/baselines_nl4opt.csv" 2>/dev/null || true
else
  echo "NL4Opt comp eval not found; skipping baselines_nl4opt.csv."
fi

# 4) Significance tests (paired bootstrap) for key comparisons
python -m training.run_significance_tests --results-dir "$RESULTS_DIR"

# 5) Threshold sweep for semantic mapping (resocratic, sbert_finetuned)
python -m training.run_mapping_threshold_sweep --results-dir "$RESULTS_DIR"

# 6) Write harder_eval_report.md (now includes CIs and significance)
python -m training.write_harder_eval_report --results-dir "$RESULTS_DIR"

# 7) Query-type breakdown (ablation B)
python -m training.run_querytype_breakdown --results-dir "$RESULTS_DIR"

